def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        base_score = 0
        if ratio > 3:
            base_score = 3000 + (ratio - 3) * 1000
        elif ratio > 2:
            base_score = 2200 + (ratio - 2) * 800
        elif ratio > 1.5:
            base_score = 1800 + (ratio - 1.5) * 400
        elif ratio > 1:
            base_score = 1500 + (ratio - 1) * 600
        else:
            series_sum = 0
            for j in range(1, 15):
                term = ((-1) ** j) * (ratio ** j) / (j * (j+1))
                series_sum += term
            multiplier = 1.0
            if capacity < item * 1.1:
                multiplier = 4
            elif capacity < item * 1.3:
                multiplier = 2
            elif capacity < item * 1.6:
                multiplier = 1.2
            else:
                multiplier = 0.6
            if abs(capacity - item) < 0.005:
                series_sum -= 0.7
            base_score = -series_sum * multiplier
        if i % 4 == 0 and base_score < 0:
            base_score *= 1.15
        elif i % 5 == 0 and base_score > 0 and not np.isinf(base_score):
            base_score += 70
        elif i % 7 == 0 and base_score > 0 and not np.isinf(base_score):
            base_score += 30
        priorities[i] = base_score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
        for i in range(n):
            if np.isinf(priorities[i]):
                priorities[i] = max_priority + 300
    else:
        priorities.fill(15000)
    for i in range(1, n):
        if priorities[i] < 0:
            adjustment = 0.15 * priorities[i-1]
            if priorities[i-1] < 0:
                adjustment *= 0.5
            priorities[i] += adjustment
    for i in range(n):
        if i > 0 and priorities[i] > 0 and priorities[i-1] > 0:
            priorities[i] += 0.05 * priorities[i-1]
        if i < n-1 and priorities[i] < 0 and priorities[i+1] < 0:
            priorities[i] *= 1.05
    return priorities
